import{_ as e,c as a,o as r,ag as o}from"./chunks/framework.S-Qvb3wi.js";const p=JSON.parse('{"title":"我們做什麽","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/What-we-do.md","filePath":"zh-TW/What-we-do.md"}'),i={name:"zh-TW/What-we-do.md"};function l(n,t,s,A,d,_){return r(),a("div",null,t[0]||(t[0]=[o('<h1 id="我們做什麽" tabindex="-1">我們做什麽 <a class="header-anchor" href="#我們做什麽" aria-label="Permalink to &quot;我們做什麽&quot;">​</a></h1><p>DGrid 以 <strong>「構建連接供需、可信高效的 AI 智能網絡」</strong> 為核心，立足於市場碎片化與中心化控制的行業痛點，打破 AI 生態的割裂與價值錯配，為 Web3 與傳統 AI 領域提供一站式解決方案。我們不僅堅持「AI 應服務於開放網絡」的核心原則，更致力於通過技術創新與生態協同，讓優質 AI 能力（包含 LLM 與 AI 代理 Agent）實現高效流動、公平分配與可信驗證。</p><p>面對模型供給爆炸但接口雜亂、開發者集成成本高、創作者價值被壟斷、推理結果不可審計等核心問題，DGrid 構建了「去中心化路由與驗證網絡 + LLM &amp; Agent 自由市場 + AI DAO」三層架構，打通從 AI 能力供給到需求匹配的全鏈路：</p><ul><li>透過統一 API 與智能路由，解決接口碎片化問題，讓開發者無需重複開發即可調用數千種模型與 Agent，大幅降低集成門檻；</li><li>以 PoQ（質量證明）算法構建可信推理環境，實現 AI 執行過程與輸出結果的可驗證、可追溯，彌補 Web3 AI 可信性缺口；</li><li>搭建開放的 LLM &amp; Agent 自由市場，讓模型提供者、提示詞工程師等創作者自主定價、直接面向全球用戶獲利，打破平台壟斷；</li><li>通過分布式節點網絡與彈性調度機制，解決中心化 AI 的高成本、單點故障與審查風險，同時為節點建設者提供按勞分配的激勵體系。</li></ul><p>最終，DGrid 旨在成為 AI 與 Web3 生態的「價值樞紐」—— 既為使用者提供性價比優越、可驗證的高質量 AI 服務，也為生態參與者搭建公平共贏的协作平台，推動 AI 從「中心化服務」升級為「開放網絡的基礎公用事業」。</p><h2 id="核心價值觀" tabindex="-1">核心價值觀 <a class="header-anchor" href="#核心價值觀" aria-label="Permalink to &quot;核心價值觀&quot;">​</a></h2><ul><li><strong>去中心化</strong>：AI 屬於開放網絡，而非集中式平臺，確保生態主體平等參與。</li><li><strong>可訪問性</strong>：任何人都可以作為節點運營商、開發者、創作者或用戶加入，降低參與門檻。</li><li><strong>無信任</strong>：基於鏈上權限與審計機制，實現服務可驗證、可追溯，無需依賴第三方信任。</li><li><strong>可擴展性</strong>：模塊化設計使模型部署、推理和緩存具有靈活性，適配多場景需求。</li><li><strong>價值可發現</strong>：通過智能路由讓推理資源「可路由、可驗証、可比價」，實現智能流動性的高效分配。</li></ul>',7)]))}const g=e(i,[["render",l]]);export{p as __pageData,g as default};
